var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으리야아아아아아아아아아──!!","JPN":"おりゃああああああああ！！","ENG":"ERRRRRAAAGH!!","TWN":"呃啊啊啊……！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"방금 CRF로 소방 도끼를 강화한 거야?","JPN":"へえ、CRFで消防斧を強化したの？","ENG":"Did you just now enhance that firefighter axe with CRF?","TWN":"你剛剛用CRF強化了你的消防斧嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"호오, 이제 제법 카운터답게 싸우는데?","JPN":"ずいぶんとカウンターらしい戦い方になってきたじゃない。","ENG":"Ho-oh, seems like you're fighting more like a Counter now.","TWN":"呵呵，現在戰鬥起來終於有點制裁者的樣子了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"요령은 어느정도 익혔어. 카운터 무기로 이게 적합한지는 모르겠지만.","JPN":"要領はだいたいつかめた。カウンターの武器としてこれが適しているのかはわからないけど。","ENG":"I got the gist of it down. But I'm not sure if this'll do as a Counter's weapon.","TWN":"呃……雖然掌握了要領，但不知道這個適不適合當作制裁者武器。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"원래 쓰던 녀석이라서 그런지, 가장 손에 감기더라고.","JPN":"ずっと使ってきたヤツだからか、これが一番手に馴染むんだ。","ENG":"Maybe it's because I've used it for a long time, but it feels pretty good in my hands.","TWN":"大概因為是我從前用過的東西，所以手感是最好的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 좋은 판단이야.","JPN":"ふふ、いい判断よ。","ENG":"Fu fuu. Good choice.","TWN":"呵呵，也是不錯的決定。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다시 간다!","JPN":"もう一度行くぞ！","ENG":"I'm going in again!","TWN":"再來！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다들 휘말리기 싫으면 비키라고──!!","JPN":"皆巻き込まれたくなければ退け！！","ENG":"Get out of my way if you don't want to get caught in between!","TWN":"各位，不想被揮到就趕緊避開！！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"좋아! 갑피가 두꺼운 녀석은 처리했어!","JPN":"よし！　甲皮が分厚い奴らは処理した！！","ENG":"Okay! I took care of the heavy-armored one!","TWN":"很好！外殼扎實的傢伙我處理掉了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다들 화력으로 찍어 눌러!","JPN":"火力で押しやるんだ！！","ENG":"Shoot the others down with your bullets!","TWN":"大家集中火力射擊！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"방패병은 대열을 유지하면서 약진 앞으로!","JPN":"盾兵は隊列を維持しつつ前進！","ENG":"Shieldmen, maintain formation and advance!","TWN":"盾牌士兵堅守陣型，向前推進！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"이대로 함선의 강하 포인트를 확보한다!","JPN":"このまま艦船の降下ポイントを確保する！","ENG":"Secure the ship's drop point!","TWN":"繼續確保艦船著陸點！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"녀석들이 물러나기 시작했어.","JPN":"奴らが後退し始めた。","ENG":"The C.O.s have started to retreat.","TWN":"那些傢伙開始撤退了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"강하 포인트 확보 완료. 야크샤 전대 사주 경계를 유지하면서 수색을 재개한다.","JPN":"降下ポイント確保完了。ヤクシャー戦隊、周囲の警戒を維持しつつ捜索を再開する。","ENG":"Drop point secured. The Yaksha Division, survey the surroundings while resuming the search.","TWN":"著陸點已確定。夜叉戰隊，在周圍保持警戒並展開搜查工作。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"특이 사항이 발생하면 즉시 보고할 것, 이상!","JPN":"特異事項が発生次第、直ちに報告するように。以上！","ENG":"Report back immediately if anything unusual occurs!","TWN":"發現任何異常情況，請立即報告！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이봐, 토끼녀.","JPN":"なあ、ウサギ女。","ENG":"Hey, bunny ears.","TWN":"喂，兔耳朵。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……심도가 깊어질수록 느끼는 건데 말이야.","JPN":"……深度が深くなるほど、感じるんだけどさ。","ENG":"...I've been feeling this the deeper we go.","TWN":"……我感覺走得越來越深了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"보이는 풍경도 한참 동안 폐허뿐이고, 살아 움직이는 건 침식체밖에 없잖아.","JPN":"見える景色は廃墟だけだし、ここで生きて活動しているのは侵食体しかいないじゃないか。","ENG":"All I see is ruins, and the only things moving are C.O.s.","TWN":"這都好一會了，看到的只有廢墟，唯一活物只有侵蝕體。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이런 곳에서 정말 뭔가를 찾을 수 있긴 한거야?","JPN":"本当に、ここで何かを探し出せるのか？","ENG":"Are you sure we can find something in a place like this?","TWN":"在這種地方真的能找到東西嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음, 글쎄?","JPN":"うーん、そうねえ？","ENG":"Mm, I don't know.","TWN":"嗯，我也不知道。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이 심도에서 목격할 수 있는 건, 침식체나 버려진 함선 같은 고철 더미들.","JPN":"この深度で発見できるのは侵食体か捨てられた艦船などの廃物たち。","ENG":"In these depths, the only things you can see are C.O.s and piles of scrap metal from abandoned ships.","TWN":"在這個深度能看到的，只有成堆的廢鐵，侵蝕體或者廢棄的艦船。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 신체 대부분을 기계로 갈아치운 해적 정도야.","JPN":"それと、身体の大半を機械に替えた海賊ぐらいよ。","ENG":"Also, maybe pirates who have replaced most of their body parts with machinery.","TWN":"還有身體大部分被機械取代的海盜。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};